import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class SecureXSSExample {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly encoding user input using ESAPI
        String encodedUserInput = "";
        try {
            encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.err.println("Error encoding user input: " + e.getMessage());
        }

        // Outputting the properly encoded result to the console
        String output = "<div>" + encodedUserInput + "</div>";
        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
